import Link from "next/link"
import { notFound } from "next/navigation"
import { PortableText } from "@portabletext/react"
import { SectionWrapper } from "@/components/SectionWrapper"
import { H1, H2, H3 } from "@/components/Typography"
import { client } from "@/sanity/lib/client"
import { urlFor } from "@/sanity/lib/image"
import type { SanityImageSource } from "@sanity/image-url/lib/types/types"

type Project = {
  _id: string
  title: string
  slug: { current: string }
  category?: string
  mainImage?: SanityImageSource
  overviewRole?: string
  overviewTimeline?: string
  overviewTools?: string
  content?: any[]
}

async function getProjectBySlug(slug: string): Promise<Project | null> {
  return client.fetch(
    `*[_type == "project" && slug.current == $slug][0]{
      _id,
      title,
      slug,
      category,
      mainImage{
        ...,
        asset->
      },
      "overviewRole": role,
      "overviewTimeline": timeline,
      "overviewTools": tools,
      content
    }`,
    { slug },
  )
}

export default async function ProjectDetailPage({
  params,
}: {
  params: { id: string }
}) {
  const { id } = params
  const project = await getProjectBySlug(id)

  if (!project) notFound()

  return (
    <div className="bg-surface">
      <section className="pt-12">
        <SectionWrapper>
          <div className="mb-4">
            <Link
              href="/projects"
              className="text-xs font-medium text-zinc-500 hover:text-zinc-900"
            >
              ← Back to projects
            </Link>
          </div>

          <div className="rounded-3xl border border-zinc-200 bg-white p-6 md:p-10">
            <p className="text-sm font-medium text-zinc-600">
              {project.category ?? "Case study"}
            </p>
            <H1 className="mt-3">{project.title}</H1>
            <p className="mt-4 max-w-3xl text-base leading-relaxed text-zinc-600">
              {/* Optional short description can come from the first block of content */}
              {Array.isArray(project.content) && project.content[0]?.children?.[0]?.text
                ? project.content[0].children[0].text
                : "A UX/UI case study from my portfolio."}
            </p>

            <div className="mt-8 aspect-video w-full overflow-hidden rounded-2xl bg-gradient-to-br from-zinc-100 to-zinc-200">
              {project.mainImage ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img
                  src={urlFor(project.mainImage).width(1200).height(675).fit("crop").url()}
                  alt={project.title}
                  className="h-full w-full object-cover"
                />
              ) : null}
            </div>
          </div>
        </SectionWrapper>
      </section>

      <section className="py-12">
        <SectionWrapper>
          <div className="grid gap-6 rounded-3xl border border-zinc-200 bg-white p-6 md:grid-cols-3 md:p-10">
            <div>
              <p className="text-xs font-semibold uppercase tracking-wide text-zinc-500">
                Role
              </p>
              <p className="mt-2 text-sm font-medium text-brand-primary">
                {project.overviewRole ?? "UX/UI Design Lead"}
              </p>
            </div>
            <div>
              <p className="text-xs font-semibold uppercase tracking-wide text-zinc-500">
                Timeline
              </p>
              <p className="mt-2 text-sm font-medium text-brand-primary">
                {project.overviewTimeline ?? "Timeline coming soon"}
              </p>
            </div>
            <div>
              <p className="text-xs font-semibold uppercase tracking-wide text-zinc-500">
                Tools
              </p>
              <p className="mt-2 text-sm font-medium text-brand-primary">
                {project.overviewTools ?? "Tools coming soon"}
              </p>
            </div>
          </div>
        </SectionWrapper>
      </section>

      <section className="pb-16">
        <SectionWrapper>
          <div className="grid gap-10">
            <div className="rounded-3xl border border-zinc-200 bg-white p-6 md:p-10">
              <H2>Project Overview</H2>
              {Array.isArray(project.content) && project.content.length > 0 ? (
                <div className="mt-4 max-w-3xl space-y-3 text-sm leading-relaxed text-zinc-600">
                  <PortableText
                    value={project.content}
                    components={{
                      block: {
                        normal: ({ children }) => <p>{children}</p>,
                      },
                    }}
                  />
                </div>
              ) : null}
            </div>
          </div>
        </SectionWrapper>
      </section>
    </div>
  )
}

